import { defineChain, type Chain } from 'viem';

export interface ChainContracts {
  announcer: string;
  registry: string;
  nameRegistry: string;
  walletFactory: string;
  legacyWalletFactory: string;
  dustPool: string | null;
  dustPoolVerifier: string | null;
  subAccount7702: string | null;
  nameRegistryMerkle: string | null;
  nameVerifier: string | null;
  // DustPool V2 (ZK-UTXO)
  dustPoolV2: string | null;
  dustPoolV2Verifier: string | null;
  dustPoolV2SplitVerifier: string | null;
  // ZK exclusion compliance verifier
  dustPoolV2ComplianceVerifier: string | null;
  // DustSwap V2 adapter (standalone, uses PrivacyAMM)
  dustSwapAdapterV2: string | null;
  dustSwapVanillaPoolKey: {
    currency0: string;
    currency1: string;
    fee: number;
    tickSpacing: number;
    hooks: string;
  } | null;
}

export interface ChainCreationCodes {
  wallet: string;
  legacyWallet: string;
}

export type ChainIconFamily = 'polkadot';

export interface ChainConfig {
  id: number;
  name: string;
  rpcUrl: string; // Primary RPC URL (for backward compatibility)
  rpcUrls: string[]; // All RPC URLs for fallback transport
  nativeCurrency: { name: string; symbol: string; decimals: number };
  blockExplorerUrl: string;
  viemChain: Chain;
  contracts: ChainContracts;
  creationCodes: ChainCreationCodes;
  deploymentBlock: number;
  dustPoolDeploymentBlock: number | null;
  supportsEIP7702: boolean;
  canonicalForNaming: boolean;
  testnet: boolean;
  isL2: boolean;
  iconFamily: ChainIconFamily;
}

