// ─── Registry ──────────────────────────────────────────────────────────────────

const CHAIN_CONFIGS: Record<number, ChainConfig> = {
  [POLKADOT_HUB_TESTNET_CONFIG.id]: POLKADOT_HUB_TESTNET_CONFIG,
};

export const DEFAULT_CHAIN_ID = 420420417;

export const CANONICAL_NAMING_CHAIN_ID = 420420417;

export function getChainConfig(chainId?: number): ChainConfig {
  const id = chainId ?? DEFAULT_CHAIN_ID;
  const config = CHAIN_CONFIGS[id];
  if (!config) {
    throw new Error(`Unsupported chain: ${id}. Supported: ${Object.keys(CHAIN_CONFIGS).join(', ')}`);
  }
  return config;
}

export function getSupportedChains(): ChainConfig[] {
  return Object.values(CHAIN_CONFIGS);
}

export function getSupportedViemChains(): Chain[] {
  return Object.values(CHAIN_CONFIGS).map(c => c.viemChain);
}

export function isChainSupported(chainId: number): boolean {
  return chainId in CHAIN_CONFIGS;
}

export function getCanonicalNamingChain(): ChainConfig {
  const chain = Object.values(CHAIN_CONFIGS).find(c => c.canonicalForNaming);
  if (!chain) throw new Error('No canonical naming chain configured');
  return chain;
}

export function isL2Chain(chainId: number): boolean {
  try {
    return getChainConfig(chainId).isL2;
  } catch {
    return false;
  }
}

// Polkadot Hub gas is very cheap but existential deposit is 0.01 DOT
export function getMinClaimableBalance(_chainId: number): number {
  return 0.01;
}

/** @deprecated Use getMinClaimableBalance(chainId) instead */
export const MIN_CLAIMABLE_BALANCE = 0.01;

